import{_ as i,c as a,o as n,a3 as l}from"./chunks/framework.DqsPtFs4.js";const d=JSON.parse('{"title":"爬虫协议 robots","description":"","frontmatter":{},"headers":[],"relativePath":"tools/questions/robots.md","filePath":"tools/questions/robots.md"}'),t={name:"tools/questions/robots.md"};function p(h,s,k,e,F,o){return n(),a("div",null,s[0]||(s[0]=[l(`<h1 id="爬虫协议-robots" tabindex="-1">爬虫协议 robots <a class="header-anchor" href="#爬虫协议-robots" aria-label="Permalink to &quot;爬虫协议 robots&quot;">​</a></h1><p>Robots 协议(也称为爬虫协议、机器人协议等)全称是“网络爬虫排除标准”(Robots Exclusion Protocol)，网站通过 Robots 协议告诉搜索引擎哪些页面可以抓取，哪些页面不能抓取。</p><p><strong>为什么需要 Robots 协议？</strong></p><ul><li>保护网站隐私和敏感信息：某些页面可能包含用户个人数据、内部运营数据、未公开的内容等，网站管理员可以通过 Robots 协议阻止搜索引擎或其他爬虫获取这些敏感信息，防止信息泄露。</li><li>控制爬虫访问频率：爬虫过度频繁地访问网站可能会消耗大量服务器资源，影响网站的正常运行和其他用户的访问体验。Robots 协议可以限制爬虫在一定时间内的访问次数，避免对服务器造成过大压力。</li><li>引导爬虫抓取重点内容：网站管理员可以通过 Robots 协议明确告诉爬虫哪些页面是对用户有价值且希望被收录和展示的，引导爬虫优先抓取这些页面，提高网站重要内容在搜索引擎结果中的曝光率。</li></ul><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>Robots 协议是网络爬虫协议，用于告诉搜索引擎哪些页面可以抓取，哪些页面不能抓取。Robots 协议由 Google、Yahoo、Bing 等搜索引擎公司提出，并成为互联网上所有搜索引擎的标准协议。Robots 协议由两段组成，第一段是 robots.txt 文件，第二段是 robots meta 标签。</p><ol><li>robots.txt 文件是服务器上的一个文件，里面包含着搜索引擎爬虫可以抓取的页面列表。 robots.txt 文件通常位于网站根目录下，例如：www.example.com/robots.txt。 robots.txt 文件可以包含多个规则，每个规则都是一个 URL 地址，用正则表达式表示。例如：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 所有搜索引擎</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">User-agent:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 百度的搜索机器人</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">User-agent:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Baiduspider</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 禁止爬寻admin目录下面的目录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Disallow:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /admin/</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 禁止抓取网页所有的.jpg格式的图片</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Disallow:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /.jpg</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 允许访问以&quot;.html&quot;为后缀的URL</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Allow:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .html</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 允许爬虫抓取所有页面</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Allow:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">User-agent:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 这里的</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">代表的所有的搜索引擎种类，</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">是一个通配符</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Disallow:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /admin/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 这里定义是禁止爬寻admin目录下面的目录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Disallow:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /require/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 这里定义是禁止爬寻require目录下面的目录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Disallow:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /ABC/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 这里定义是禁止爬寻ABC目录下面的目录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Disallow:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /cgi-bin/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.htm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 禁止访问/cgi-bin/目录下的所有以&quot;.htm&quot;为后缀的URL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">包含子目录</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">。</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Disallow:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">?</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 禁止访问网站中所有包含问号</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (?) 的网址</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Disallow:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /.jpg</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">禁止抓取网页所有的.jpg格式的图片</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Disallow:/ab/adc.html</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 禁止爬取ab文件夹下面的adc.html文件。</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Allow:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /cgi-bin/　这里定义是允许爬寻cgi-bin目录下面的目录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Allow:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 这里定义是允许爬寻tmp的整个目录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Allow:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .htm</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">仅允许访问以&quot;.htm&quot;为后缀的URL。</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Allow:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .gif</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">允许抓取网页和gif格式图片</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Sitemap:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 网站地图</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 告诉爬虫这个页面是网站地图</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 告诉爬虫可以在该地址找到网站地图文件</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Sitemap:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://www.example.com/sitemap.xml</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 用来指定robot协议的版本号</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Robot-version:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2.0</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在8:00到13:00之间,以每分钟12次的频率进行访问</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Request-rate:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 12/1m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0800</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1300</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#允许在凌晨1:00到13:00访问</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Visit-time:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0100-1300</span></span></code></pre></div><ol start="2"><li>Robots.txt 文件主要是限制整个站点或者目录的搜索引擎访问情况，而 Robots Meta 标签则主要是针对一个个具体的页面。和其他的 META 标签（如使用的语言、页面的描述、关键词等）一样，Robots Meta 标签也是放在页面中，专门用来告诉搜索引擎 ROBOTS 如何抓取该页的内容。</li></ol><p>Robots Meta 标签中没有大小写之分，name=”Robots”表示所有的搜索引擎，可以针对某个具体搜索引擎写为 name=”BaiduSpider”。content 部分有四个指令选项：index、noindex、follow、nofollow，指令间以“,”分隔。</p><ul><li>index 指令告诉搜索机器人抓取该页面；</li><li>noindex 指令表示搜索机器人不要抓取该页面；</li><li>follow 指令表示搜索机器人可以沿着该页面上的链接继续抓取下去；</li><li>nofollow 指令表示搜索机器人不要沿着该页面上的链接继续抓取下去。</li><li>Robots Meta 标签的缺省值是 index 和 follow</li></ul>`,11)]))}const g=i(t,[["render",p]]);export{d as __pageData,g as default};
